const html = $input.first().json.data || $input.first().json;
const htmlStr = typeof html === 'string' ? html : JSON.stringify(html);
const cookieStr = $('Cookies holen').first().json.cookieString || '';
const results = [];
const foundIds = new Set();
const tokens = [];
let m;

const rx1 = /data-day="(\d{2})\.(\d{2})\.(\d{4})"/g;
while ((m = rx1.exec(htmlStr)) !== null) {
  tokens.push({ pos: m.index, type: 'date', d: m[1], mo: m[2], y: m[3] });
}
const rx2 = /(?:^|>)[^<]*?(\d{2})\.(\d{2})\.(\d{4})[^<]*?(?=<)/g;
while ((m = rx2.exec(htmlStr)) !== null) {
  if (!tokens.find(t => t.type === 'date' && Math.abs(t.pos - m.index) < 100)) {
    tokens.push({ pos: m.index, type: 'date', d: m[1], mo: m[2], y: m[3] });
  }
}
const rx3 = /href="(https?:\/\/www\.joyclub\.de\/event\/(\d+)\.([^"]+)\.html)(?:#[^"]*)?">/g;
while ((m = rx3.exec(htmlStr)) !== null) {
  tokens.push({ pos: m.index, type: 'link', url: m[1].split('#')[0], id: m[2], slug: m[3] });
}
tokens.sort((a, b) => a.pos - b.pos);

let curDate = '', curIso = '';
const candidates = [];
for (const token of tokens) {
  if (token.type === 'date') {
    curDate = token.d + '.' + token.mo + '.' + token.y;
    curIso  = token.y + '-' + token.mo + '-' + token.d;
  } else if (token.type === 'link' && curDate && !foundIds.has(token.id)) {
    foundIds.add(token.id);
    const nameCtx = htmlStr.substring(Math.max(0, token.pos - 100), token.pos + 600);
    let EventName = '';
    const linkTextM = nameCtx.match(/href="[^"]*">([^<]{3,120})</);
    if (linkTextM) EventName = linkTextM[1].replace(/[\n\r\t]+/g,' ').replace(/\s+/g,' ').trim().replace(/\d{2}\.\d{2}\.\d{4}/g,'').trim();
    if (!EventName) {
      const nameM = nameCtx.match(/class="[^"]*event_name[^"]*"[^>]*>([\s\S]*?)<\/(?:h2|span|div|p)>/i);
      if (nameM) EventName = nameM[1].replace(/<[^>]+>/g,'').trim();
    }
    if (!EventName || EventName.length < 3) {
      EventName = token.slug.replace(/_/g,' ').replace(/\b\w/g,c=>c.toUpperCase()).substring(0,80);
    }
    if (EventName.length >= 3) {
      candidates.push({ EventName, EventDatum: curDate, isoDatum: curIso, EventLink: token.url, joyId: token.id });
    }
  }
}

if (candidates.length === 0) {
  return [{ json: { error: 'Keine Events gefunden', htmlLength: htmlStr.length } }];
}

const today = new Date(); today.setHours(0,0,0,0);

const checkEvent = async (ev) => {
  try {
    const detailHtml = await this.helpers.httpRequest({
      method: 'GET', url: ev.EventLink,
      headers: {
        Cookie: cookieStr,
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 Chrome/122.0.0.0 Safari/537.36',
        Accept: 'text/html,application/xhtml+xml', 'Accept-Language': 'de-DE,de;q=0.9'
      },
      timeout: 20000
    });
    const detailStr = typeof detailHtml === 'string' ? detailHtml : JSON.stringify(detailHtml);

    // Abgesagt oder verschoben?
    const isAbgesagt  = /abgesagt/i.test(detailStr);
    const isVerschoben = /verschoben/i.test(detailStr);
    const isDeactivated = isAbgesagt || isVerschoben;
    const _grund = isAbgesagt ? 'abgesagt' : isVerschoben ? 'verschoben' : null;

    // Datum von Detailseite (frühestes zukünftiges)
    let EventDatum = ev.EventDatum, isoDatum = ev.isoDatum;
    const dateRe = /(\d{2})\.(\d{2})\.(\d{4})/g;
    const futureDates = [];
    let dm;
    while ((dm = dateRe.exec(detailStr)) !== null) {
      const [, d, mo, y] = dm;
      const dt = new Date(+y, +mo-1, +d);
      if (dt >= today) futureDates.push({ dt, EventDatum: d+'.'+mo+'.'+y, isoDatum: y+'-'+mo+'-'+d });
    }
    if (futureDates.length > 0) {
      futureDates.sort((a,b) => a.dt-b.dt);
      EventDatum = futureDates[0].EventDatum;
      isoDatum   = futureDates[0].isoDatum;
    }

    console.log((isDeactivated ? '✗ ['+_grund+']' : '✓') + ' ' + ev.EventName + ' → ' + EventDatum);
    return { ...ev, EventDatum, isoDatum, _deactivated: isDeactivated, _grund };
  } catch(e) {
    console.log('Fehler ' + ev.joyId + ':', e.message);
    return { ...ev, _deactivated: false, _grund: null };
  }
};

const checked = await Promise.all(candidates.map(checkEvent));

const active = checked.filter(ev => !ev._deactivated).length;
const inactive = checked.filter(ev => ev._deactivated).length;
console.log('Gesamt: ' + checked.length + ' | Aktiv: ' + active + ' | Abgesagt/Verschoben: ' + inactive);

// ALLE Events zurückgeben – auch abgesagte (mit _grund)
return checked.map(({ joyId, ...ev }) => ({ json: ev }));

const scraped  = $('HTML parsen').all().map(i => i.json);
const dbEvents = $input.first().json.list || [];

const getJoyId = url => { const m = url && url.match(/\/event\/(\d+)[./]/); return m ? m[1] : null; };

const scrapedIds = new Set(scraped.map(e => getJoyId(e.EventLink)).filter(Boolean));
const dbMap = new Map();
for (const ev of dbEvents) {
  const id = getJoyId(ev.EventLink);
  if (id) dbMap.set(id, ev);
}

const results = [];
for (const ev of scraped) {
  const id = getJoyId(ev.EventLink);
  if (!id) continue;

  // Explizit abgesagt/verschoben → sofort deaktivieren
  if (ev._deactivated) {
    if (dbMap.has(id)) {
      results.push({ json: { ...ev, _action: 'deactivate', _id: dbMap.get(id).Id } });
    }
    // Nicht in DB → ignorieren (kein neues inaktives Event anlegen)
    continue;
  }

  // Aktive Events
  if (!dbMap.has(id)) {
    results.push({ json: { ...ev, _action: 'create' } });
  } else {
    results.push({ json: { ...ev, _action: 'update', _id: dbMap.get(id).Id } });
  }
}

// DB-Events die komplett von JOYclub verschwunden sind → deaktivieren
for (const ev of dbEvents) {
  const id = getJoyId(ev.EventLink);
  if (id && !scrapedIds.has(id)) {
    results.push({ json: { ...ev, _action: 'deactivate', _id: ev.Id } });
  }
}

const byAction = results.reduce((a,r) => { a[r.json._action]=(a[r.json._action]||0)+1; return a; }, {});
console.log('Vergleichen: scraped='+scraped.length+' db='+dbEvents.length+' →', JSON.stringify(byAction));
return results.length ? results : [{ json: { _action: 'noop', info: 'Keine Änderungen' } }];

