const cookie = $('Cookies holen').first().json.cookieString || '';
const toInt = str => str ? parseInt(str.replace(/[^\d]/g, ''), 10) : 0;

const eventsResp = await this.helpers.httpRequest({
  method: 'GET',
  url: 'http://f3-cookie-crawler:3000/api/events?status=aktiv'
});
const events = eventsResp.list || [];
const results = [];
const knowledge = [];

for (const event of events) {
  const { Id, EventName, EventDatum, EventLink } = event;
  if (!EventLink) continue;
  console.log('Scraping Event ' + Id + ': ' + EventLink);

  let html = '';
  try {
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url: EventLink,
      headers: {
        Cookie: cookie,
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 Chrome/122.0.0.0 Safari/537.36',
        Accept: 'text/html,application/xhtml+xml',
        'Accept-Language': 'de-DE,de;q=0.9'
      },
      timeout: 25000,
      followRedirects: true
    });
    html = typeof resp === 'string' ? resp : JSON.stringify(resp);
  } catch(e) {
    console.log('Fetch error Event ' + Id + ':', e.message);
    results.push({ json: { Id, status: 'fetch_error', error: e.message } });
    continue;
  }

  // Deaktivierungserkennung
  const isAbgesagt   = /abgesagt/i.test(html);
  const isVerschoben = /verschoben/i.test(html);
  if (isAbgesagt || isVerschoben) {
    const deaktStatus = isAbgesagt ? 'abgesagt' : 'verschoben';
    try {
      await this.helpers.httpRequest({
        method: 'PATCH',
        url: 'http://f3-cookie-crawler:3000/api/events/' + Id,
        headers: { 'Content-Type': 'application/json' },
        body: { Status: deaktStatus },
        json: true
      });
    } catch(e) {}
    results.push({ json: { Id, status: 'deaktiviert', grund: deaktStatus } });
    console.log('Event ' + Id + ': deaktiviert (' + deaktStatus + ')');
    continue;
  }

  const patch = {};

  // ── Stats ──
  const angemeldetM  = html.match(/(\d+)\s*Personen angemeldet/);
  const nichtBestM   = html.match(/(\d+)\s*noch nicht best.tigt/) || html.match(/(\d+)\s*nicht best.tigt/);
  const vorgemerktM  = html.match(/(\d+)\s*mal vorgemerkt/);
  const aufrufM      = html.match(/(\d+)\s*Aufrufe/);
  const maennerM     = html.match(/M.nner[^(]*\((\d+)\)/);
  const frauenM      = html.match(/Frauen[^(]*\((\d+)\)/);
  const paareM       = html.match(/Paare[^(]*\((\d+)\)/);

  patch.Angemeldet      = angemeldetM  ? toInt(angemeldetM[1])  : 0;
  patch.NichtBestaetigt = nichtBestM   ? toInt(nichtBestM[1])   : 0;
  patch.Vorgemerkt      = vorgemerktM  ? toInt(vorgemerktM[1])  : 0;
  patch.Aufrufe         = aufrufM      ? toInt(aufrufM[1])      : 0;
  patch.Maenner         = maennerM     ? toInt(maennerM[1])     : 0;
  patch.Frauen          = frauenM      ? toInt(frauenM[1])      : 0;
  patch.Paare           = paareM       ? toInt(paareM[1])       : 0;

  // ── Event-Bild ──
  if (!event.EventBild) {
    const imgM = html.match(/data-overlay-image-ui-data="([^"]+)"/);
    if (imgM) {
      const dec = imgM[1].replace(/&quot;/g,'"').replace(/&amp;/g,'&').replace(/\\\//g,'/');
      try {
        const d = JSON.parse(dec);
        const srcs = (d.fallback_image_source_set||{}).source_list||[];
        const best = srcs.find(s=>s.width>=800)||srcs[srcs.length-1];
        if (best&&best.resource_path) patch.EventBild = best.resource_path;
      } catch(e) {}
    }
  }

  // ── Beschreibung ──
  const descM = html.match(/class="event_description brkwrd"[^>]*>([\s\S]*?)(?=<div class="[^"]*event_detail_tab|<div id="guest_list|<div class="clearfix[^"]*">\s*<\/div>)/);
  let beschreibung = '';
  if (descM) {
    let raw = descM[1].replace(/<div[^>]*image-ui[^>]*>[\s\S]*?<\/div>/g,'');
    beschreibung = raw.replace(/<[^>]+>/g,' ').replace(/&[^;]+;/g,' ').replace(/\s+/g,' ').trim();
    if (beschreibung.length > 20) patch['Event-Beschreibung'] = beschreibung.substring(0,1000);
  }

  // ── Preise ──
  // Preistabelle: #event_anmeldung_price_list
  // Zeilen: #event_anmeldung_genderw (Frau), #event_anmeldung_genderm (Mann)
  // Spalten: td.price_hi (Standard), td.price_normal / span darin (Premium)
  const parsePrice = str => str ? str.replace(/&nbsp;/g,' ').replace(/[^\d,. €]/g,'').trim() : '';

  let preiseFrauStd = '', preiseFrauPremium = '', preiseMannStd = '', preiseMannPremium = '';

  // Frau
  const frauRow = html.match(/id="event_anmeldung_genderw"[^>]*>[\s\S]*?<\/tr>/);
  if (frauRow) {
    preiseFrauStd     = parsePrice((frauRow[0].match(/class="[^"]*price_hi[^"]*">([^<]+)/)||[])[1]);
    preiseFrauPremium = parsePrice((frauRow[0].match(/class="[^"]*price_normal[^"]*">[\s\S]*?<span>([^<]+)<\/span>/)||
                                    frauRow[0].match(/class="[^"]*price_normal[^"]*">([^<\s][^<]+)/)||[])[1]);
  }

  // Mann
  const mannRow = html.match(/id="event_anmeldung_genderm"[^>]*>[\s\S]*?<\/tr>/);
  if (mannRow) {
    preiseMannStd     = parsePrice((mannRow[0].match(/class="[^"]*price_hi[^"]*">([^<]+)/)||[])[1]);
    preiseMannPremium = parsePrice((mannRow[0].match(/class="[^"]*price_normal[^"]*">[\s\S]*?<span>([^<]+)<\/span>/)||
                                    mannRow[0].match(/class="[^"]*price_normal[^"]*">([^<\s][^<]+)/)||[])[1]);
  }

  // Preise als lesbarer String
  let preise = '';
  if (preiseFrauStd || preiseMannStd) {
    const parts = [];
    if (preiseFrauStd)     parts.push('Frau: ' + preiseFrauStd + (preiseFrauPremium ? ' (Premium: ' + preiseFrauPremium + ')' : ''));
    if (preiseMannStd)     parts.push('Mann: ' + preiseMannStd + (preiseMannPremium ? ' (Premium: ' + preiseMannPremium + ')' : ''));
    preise = parts.join(' | ');
  } else {
    // Fallback: alter Regex
    const preisBlock = html.match(/(?:Eintritt|Preise?|Ticketpreise?)[\s\S]{0,800}(?=<\/(?:div|section)|Dresscode|<h[23])/i);
    if (preisBlock) preise = preisBlock[0].replace(/<[^>]+>/g,' ').replace(/&[^;]+;/g,' ').replace(/\s+/g,' ').trim().substring(0,400);
  }



  // ── Dresscode ──
  let dresscode = '';
  const dressM = html.match(/(?:Dresscode|Dress[- ]?Code)[^<]{0,400}(?=<\/(?:div|p|li)|Eintritt|Preise)/i)
               || html.match(/(?:Dresscode|Dress[- ]?Code)([\s\S]{0,400}?)(?=<(?:div|p|ul|br))/i);
  if (dressM) dresscode = dressM[0].replace(/<[^>]+>/g,' ').replace(/\s+/g,' ').trim().substring(0,300);
  if (preise)    patch.Preise    = preise;
  if (dresscode) patch.Dresscode = dresscode;

  // ── Uhrzeit ──
  let uhrzeit = '';
  const zeitM = html.match(/(\d{1,2}:\d{2})\s*(?:Uhr)?\s*(?:Einlass|Beginn|Start|ab)/i)
              || html.match(/(?:Einlass|Beginn|Start|ab)\s*(\d{1,2}:\d{2})/i);
  if (zeitM) uhrzeit = zeitM[1];

  // ── DB Update ──
  try {
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: 'http://f3-cookie-crawler:3000/api/events/' + Id,
      headers: { 'Content-Type': 'application/json' },
      body: patch,
      json: true
    });
    results.push({ json: { Id, status: 'ok', ...patch } });
    console.log('Event ' + Id + ': Angemeldet=' + patch.Angemeldet + ' Aufrufe=' + patch.Aufrufe + ' Preise=' + !!preise + ' Dresscode=' + !!dresscode);
  } catch(e) {
    results.push({ json: { Id, status: 'patch_error', error: e.message } });
  }

  knowledge.push({
    id: Id,
    name: EventName,
    datum: EventDatum,
    link: EventLink,
    preise: preise || '(nicht gefunden)',
    dresscode: dresscode || '(nicht angegeben)',
    beschreibung: beschreibung ? beschreibung.substring(0,1500) : '(keine Beschreibung)',
    uhrzeit: uhrzeit || '',
    scrapedAt: new Date().toISOString()
  });
}

// ── Status Store: Events ──
try {
  const all = await this.helpers.httpRequest({ method:'GET', url:'http://f3-cookie-crawler:3000/api/events?status=aktiv' });
  await this.helpers.httpRequest({
    method:'POST', url:'http://f3-cookie-crawler:3000/status',
    headers:{'Content-Type':'application/json'},
    body:{ key:'events', data:{ events: all.list||[], updatedAt: new Date().toISOString() } }, json:true
  });
} catch(e) { console.log('Status Store events error:', e.message); }

// ── Status Store: Knowledge Base ──
if (knowledge.length > 0) {
  try {
    await this.helpers.httpRequest({
      method:'POST', url:'http://f3-cookie-crawler:3000/status',
      headers:{'Content-Type':'application/json'},
      body:{ key:'event-knowledge', data:{ knowledge, count: knowledge.length, updatedAt: new Date().toISOString() } }, json:true
    });
    console.log('Knowledge Base gespeichert: ' + knowledge.length + ' Events');
  } catch(e) { console.log('Knowledge Base save error:', e.message); }
}

return results;

const storeData = $('📦 Status-Store lesen').first().json;
const events = (storeData && storeData.events && storeData.events.length > 0)
  ? storeData.events : [];
console.log('[EventsAPI] Status-Store:', events.length, 'Events');
return [{ json: { _response: JSON.stringify(events) } }];

const cookie = $('🍪 Cookies holen (Stats)').first().json.list?.[0]?.Cookie || '';
const events = ($('📋 Aktive Events holen').first().json.list || [])
  .filter(e => e.EventLink && e.EventLink.trim() !== '');

const toInt = str => str ? parseInt(str.replace(/[^\d]/g, ''), 10) : 0;
const results = [];

for (const event of events) {
  const { Id, EventLink } = event;
  let html = '';
  try {
    const resp = await this.helpers.httpRequest({
      method: 'GET', url: EventLink,
      headers: { Cookie: cookie, 'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 Chrome/120.0.0.0 Safari/537.36' },
      timeout: 20000
    });
    html = typeof resp === 'string' ? resp : JSON.stringify(resp);
  } catch(e) {
    results.push({ json: { Id, status: 'fetch_error', error: e.message } });
    continue;
  }

  const toMatch = (re) => { const m = html.match(re); return m ? toInt(m[1]) : 0; };
  const stats = {
    Angemeldet:      toMatch(/(\d+)\s*Personen angemeldet/) || toMatch(/>( \d+)<[^>]*>\s*Personen angemeldet/),
    NichtBestaetigt: toMatch(/(\d+)\s*noch nicht bestätigt/),
    Vorgemerkt:      toMatch(/(\d+)\s*mal vorgemerkt/),
    Aufrufe:         toMatch(/(\d+)\s*Aufrufe/),
    Maenner:         toMatch(/Männer[^(]*\((\d+)\)/) || toMatch(/M.nner[^(]*\((\d+)\)/),
    Frauen:          toMatch(/Frauen[^(]*\((\d+)\)/),
    Paare:           toMatch(/Paare[^(]*\((\d+)\)/)
  };

  await this.helpers.httpRequest({
    method: 'PATCH',
    url: 'http://f3-cookie-crawler:3000/api/events/' + Id,
    headers: { 'Content-Type': 'application/json' },
    body: stats, json: true
  });
  results.push({ json: { Id, status: 'ok', ...stats } });
}

// Status-Store aktualisieren
const statusEvents = results.filter(r => r.json.status === 'ok').map(r => {
  const orig = events.find(e => e.Id === r.json.Id) || {};
  return { ...orig, ...r.json };
});
await this.helpers.httpRequest({
  method: 'POST', url: 'http://f3-cookie-crawler:3000/status',
  headers: { 'Content-Type': 'application/json' },
  body: { key: 'events', data: { events: statusEvents, updatedAt: new Date().toISOString() } },
  json: true
});

console.log('Stats-Refresh: ' + results.length + ' Events aktualisiert');
return results;

const cookieStr = $input.first().json.cookieString || '';

const PROFILE_URL = 'https://www.joyclub.de/party/13140845.f3.html';
const headers = {
  Cookie: cookieStr,
  'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 Chrome/122.0.0.0 Safari/537.36',
  Accept: 'text/html,application/xhtml+xml',
  'Accept-Language': 'de-DE,de;q=0.9'
};

// 1. F3-Profil laden → profile_homepage_element Links
let profileHtml;
try {
  profileHtml = await this.helpers.httpRequest({ method: 'GET', url: PROFILE_URL, headers, timeout: 20000 });
} catch(e) {
  return [{ json: { ok: false, error: 'Profil laden fehlgeschlagen: ' + e.message } }];
}

const linkRe = /href="(https?:\/\/www\.joyclub\.de\/party\/homepage\/[^"]+\.html)"/g;
const links = [];
let lm;
while ((lm = linkRe.exec(profileHtml)) !== null) {
  if (!links.includes(lm[1])) links.push(lm[1]);
}

if (links.length === 0) {
  return [{ json: { ok: false, error: 'Keine Profil-Seiten gefunden', profileLength: profileHtml.length } }];
}
console.log('Profil-Seiten gefunden:', links.length);

// 2. Jede Seite laden + Text extrahieren
const fetchPage = async (url) => {
  try {
    const html = await this.helpers.httpRequest({ method: 'GET', url, headers, timeout: 20000 });
    const slugMatch = url.match(/\d+-\d+\.([^.]+)\.html$/);
    const slug = slugMatch ? slugMatch[1].replace(/_/g, ' ') : url;

    // Titel der Seite
    const titleMatch = html.match(/<h1[^>]*>([^<]+)<\/h1>/i) || html.match(/<title>([^<|]+)/i);
    const title = titleMatch ? titleMatch[1].trim() : slug;

    // Content aus .profile_homepage_element oder body
    let contentHtml = '';
    const contentM = html.match(/class="[^"]*profile_homepage_element[^"]*"[^>]*>([\s\S]*?)<\/div>/i)
                  || html.match(/id="content"[^>]*>([\s\S]*?)<\/(?:div|main|section)>/i)
                  || html.match(/<(?:main|article)[^>]*>([\s\S]*?)<\/(?:main|article)>/i);
    if (contentM) {
      contentHtml = contentM[1];
    } else {
      const bodyM = html.match(/<body[^>]*>([\s\S]*?)<\/body>/i);
      if (bodyM) contentHtml = bodyM[1];
    }

    const text = contentHtml
      .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
      .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
      .replace(/<[^>]+>/g, ' ')
      .replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>')
      .replace(/\s+/g, ' ').trim().substring(0, 4000);

    console.log('✓', title, '–', text.length, 'Zeichen');
    return { url, title, slug, text };
  } catch(e) {
    console.log('✗', url, '–', e.message);
    return { url, title: url, slug: url, text: '', error: e.message };
  }
};

const pages = await Promise.all(links.map(fetchPage));
const successful = pages.filter(p => p.text && p.text.length > 50).length;
console.log('Geladen:', successful + '/' + pages.length);

// 3. Status-Store: profile-knowledge
try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: 'http://f3-cookie-crawler:3000/status',
    headers: { 'Content-Type': 'application/json' },
