        Cookie: cookieStr,
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 Chrome/122.0.0.0 Safari/537.36',
        Accept: 'text/html,application/xhtml+xml', 'Accept-Language': 'de-DE,de;q=0.9'
      },
      timeout: 20000
    });
    const detailStr = typeof detailHtml === 'string' ? detailHtml : JSON.stringify(detailHtml);

    // Abgesagt oder verschoben?
    const isAbgesagt  = /abgesagt/i.test(detailStr);
    const isVerschoben = /verschoben/i.test(detailStr);
    const isDeactivated = isAbgesagt || isVerschoben;
    const _grund = isAbgesagt ? 'abgesagt' : isVerschoben ? 'verschoben' : null;

    // Datum von Detailseite (frühestes zukünftiges)
    let EventDatum = ev.EventDatum, isoDatum = ev.isoDatum;
    const dateRe = /(\d{2})\.(\d{2})\.(\d{4})/g;
    const futureDates = [];
    let dm;
    while ((dm = dateRe.exec(detailStr)) !== null) {
      const [, d, mo, y] = dm;
      const dt = new Date(+y, +mo-1, +d);
      if (dt >= today) futureDates.push({ dt, EventDatum: d+'.'+mo+'.'+y, isoDatum: y+'-'+mo+'-'+d });
    }
    if (futureDates.length > 0) {
      futureDates.sort((a,b) => a.dt-b.dt);
      EventDatum = futureDates[0].EventDatum;
      isoDatum   = futureDates[0].isoDatum;
    }

    console.log((isDeactivated ? '✗ ['+_grund+']' : '✓') + ' ' + ev.EventName + ' → ' + EventDatum);
    return { ...ev, EventDatum, isoDatum, _deactivated: isDeactivated, _grund };
  } catch(e) {
    console.log('Fehler ' + ev.joyId + ':', e.message);
    return { ...ev, _deactivated: false, _grund: null };
  }
};

