  }
};

const pages = await Promise.all(links.map(fetchPage));
const successful = pages.filter(p => p.text && p.text.length > 50).length;
console.log('Geladen:', successful + '/' + pages.length);

// 3. Status-Store: profile-knowledge
try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: 'http://f3-cookie-crawler:3000/status',
    headers: { 'Content-Type': 'application/json' },
    body: { key: 'profile-knowledge', data: { pages, count: pages.length, scrapedAt: new Date().toISOString() } },
    json: true
  });
  console.log('Status-Store: profile-knowledge gespeichert');
} catch(e) {
  console.log('Status-Store Fehler:', e.message);
}

return [{ json: { ok: true, count: pages.length, successful, scrapedAt: new Date().toISOString() } }];
